# This module represents the checkers board
import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range(0, 8, 2):
                self.board[row, col] = -1
        for row in range(5, 8):
            for col in range(0, 8, 2):
                self.board[row, col] = 1

    def display(self):
        print("   A B C D E F G H")
        print("   ---------------")
        for i, row in enumerate(self.board, start=1):
            print(f"{i} |", end="")
            for piece in row:
                if piece == -1:
                    print(' X ', end="")
                elif piece == 1:
                    print(' O ', end="")
                else:
                    print('   ', end="")
            print("|", i)
        print("   ---------------")
```

